beginning.embedded_functions:
static int em_check_invalid_syntax(const char *val) {
    if (val == NULL || val[0] == '\0')
        return 1; /* Empty syntax is invalid */
    /* Valid DICOM UIDs contain only digits and dots, starting with a digit */
    if (val[0] < '0' || val[0] > '9')
        return 1; /* Must start with digit */
    const char *p = val;
    while (*p) {
        if (*p != '.' && (*p < '0' || *p > '9'))
            return 1; /* Contains non-OID character */
        p++;
    }
    return 0;
}
